-- ============================================
-- Gizera ERP SPPG - Seed Data
-- Run after migration on fresh database
-- Usage: psql -U erp_sppg_user -d erp_sppg -f seed.sql
-- ============================================

BEGIN;

-- Disable triggers during seed
SET session_replication_role = 'replica';

-- Clean existing data (except system tables)
TRUNCATE TABLE 
  delivery_menu_items, status_transitions, electronic_pods, delivery_reviews,
  delivery_records, delivery_tasks, pickup_tasks,
  menu_item_school_allocations, menu_items, menu_plans,
  goods_receipt_items, goods_receipts, purchase_order_items, purchase_orders,
  inventory_movements, inventory_items, stok_opname_items, stok_opname_forms,
  recipe_items, recipe_versions, recipes,
  semi_finished_movements, semi_finished_production_logs, semi_finished_inventories,
  semi_finished_recipe_ingredients, semi_finished_recipes, semi_finished_goods,
  ingredients, suppliers,
  asset_maintenances, kitchen_assets,
  cash_flow_entries, budget_targets,
  attendances, employees,
  ompreng_cleanings, ompreng_inventories, ompreng_trackings,
  risk_assessment_items, risk_assessment_category_scores, risk_assessment_forms,
  sop_checklist_items, sop_categories,
  sppg_operational_snapshots,
  notifications, audit_trails,
  wi_fi_configs, gps_configs, system_configs,
  schools, users, sppgs, yayasans
CASCADE;

SELECT pg_catalog.set_config('search_path', '', false);
SELECT pg_catalog.setval('public.asset_maintenances_id_seq', 1, false);
SELECT pg_catalog.setval('public.attendances_id_seq', 154, true);
SELECT pg_catalog.setval('public.audit_trails_id_seq', 95, true);
SELECT pg_catalog.setval('public.budget_targets_id_seq', 16, true);
SELECT pg_catalog.setval('public.cash_flow_entries_id_seq', 25, true);
SELECT pg_catalog.setval('public.delivery_menu_items_id_seq', 2, true);
SELECT pg_catalog.setval('public.delivery_records_id_seq', 24, true);
SELECT pg_catalog.setval('public.delivery_reviews_id_seq', 12, true);
SELECT pg_catalog.setval('public.delivery_tasks_id_seq', 26, true);
SELECT pg_catalog.setval('public.electronic_pods_id_seq', 1, false);
SELECT pg_catalog.setval('public.employees_id_seq', 14, true);
SELECT pg_catalog.setval('public.goods_receipt_items_id_seq', 36, true);
SELECT pg_catalog.setval('public.goods_receipts_id_seq', 10, true);
SELECT pg_catalog.setval('public.gps_configs_id_seq', 2, true);
SELECT pg_catalog.setval('public.ingredients_id_seq', 35, true);
SELECT pg_catalog.setval('public.inventory_items_id_seq', 35, true);
SELECT pg_catalog.setval('public.inventory_movements_id_seq', 18, true);
SELECT pg_catalog.setval('public.kitchen_assets_id_seq', 15, true);
SELECT pg_catalog.setval('public.menu_item_school_allocations_id_seq', 240, true);
SELECT pg_catalog.setval('public.menu_items_id_seq', 20, true);
SELECT pg_catalog.setval('public.menu_plans_id_seq', 4, true);
SELECT pg_catalog.setval('public.notifications_id_seq', 12, true);
SELECT pg_catalog.setval('public.ompreng_cleanings_id_seq', 1, true);
SELECT pg_catalog.setval('public.ompreng_inventories_id_seq', 1, false);
SELECT pg_catalog.setval('public.ompreng_trackings_id_seq', 1, false);
SELECT pg_catalog.setval('public.pickup_tasks_id_seq', 1, true);
SELECT pg_catalog.setval('public.purchase_order_items_id_seq', 44, true);
SELECT pg_catalog.setval('public.purchase_orders_id_seq', 13, true);
SELECT pg_catalog.setval('public.recipe_items_id_seq', 54, true);
SELECT pg_catalog.setval('public.recipe_versions_id_seq', 1, false);
SELECT pg_catalog.setval('public.recipes_id_seq', 18, true);
SELECT pg_catalog.setval('public.risk_assessment_category_scores_id_seq', 1, false);
SELECT pg_catalog.setval('public.risk_assessment_forms_id_seq', 1, false);
SELECT pg_catalog.setval('public.risk_assessment_items_id_seq', 1, false);
SELECT pg_catalog.setval('public.schools_id_seq', 12, true);
SELECT pg_catalog.setval('public.semi_finished_goods_id_seq', 8, true);
SELECT pg_catalog.setval('public.semi_finished_inventories_id_seq', 8, true);
SELECT pg_catalog.setval('public.semi_finished_movements_id_seq', 3, true);
SELECT pg_catalog.setval('public.semi_finished_production_logs_id_seq', 1, false);
SELECT pg_catalog.setval('public.semi_finished_recipe_ingredients_id_seq', 1, false);
SELECT pg_catalog.setval('public.semi_finished_recipes_id_seq', 1, false);
SELECT pg_catalog.setval('public.sop_categories_id_seq', 1, false);
SELECT pg_catalog.setval('public.sop_checklist_items_id_seq', 1, false);
SELECT pg_catalog.setval('public.sppg_operational_snapshots_id_seq', 1, false);
SELECT pg_catalog.setval('public.sppgs_id_seq', 1, true);
SELECT pg_catalog.setval('public.status_transitions_id_seq', 36, true);
SELECT pg_catalog.setval('public.stok_opname_forms_id_seq', 1, false);
SELECT pg_catalog.setval('public.stok_opname_items_id_seq', 1, false);
SELECT pg_catalog.setval('public.suppliers_id_seq', 10, true);
SELECT pg_catalog.setval('public.system_configs_id_seq', 1, false);
SELECT pg_catalog.setval('public.users_id_seq', 17, true);
SELECT pg_catalog.setval('public.wi_fi_configs_id_seq', 2, true);
SELECT pg_catalog.setval('public.yayasans_id_seq', 1, true);

-- Re-enable triggers
SET session_replication_role = 'origin';

-- Reset sequences to max id + 1
DO $$
DECLARE
  r RECORD;
BEGIN
  FOR r IN (
    SELECT c.relname AS seq_name, t.relname AS table_name, a.attname AS col_name
    FROM pg_class c
    JOIN pg_depend d ON d.objid = c.oid
    JOIN pg_class t ON d.refobjid = t.oid
    JOIN pg_attribute a ON a.attrelid = t.oid AND a.attnum = d.refobjsubid
    WHERE c.relkind = 'S'
  ) LOOP
    EXECUTE format('SELECT setval(%L, COALESCE((SELECT MAX(%I) FROM %I), 0) + 1, false)', r.seq_name, r.col_name, r.table_name);
  END LOOP;
END $$;

COMMIT;
